Voici la structure complète de l’objet MetaScenario avec sa définition sous forme de métaclasse structurée incluant les champs attendus, leurs types, et les relations associées.

✅ Objet : MetaScenario (type : MetaObject)
jsonCopierModifier{
  "name": "MetaScenario",
  "type": "MetaObject",
  "description": {
    "FR": "Définit la structure d’un scénario exécutable, composé d’étapes hiérarchiques, validables et traçables"
  },
  "is_metaclass": true,
  "schema": {
    "id": "string",                       // Numérotation hiérarchique de l'étape
    "name": { "FR": "string" },          // Nom de l'étape ou du scénario
    "description": { "FR": "string" },   // Description de l'étape
    "type": "string",                    // "scenario"
    "delay": "string|null",              // Délai prévu entre cette étape et la suivante
    "steps": ["MetaScenario"],           // Sous-étapes (récursif)
    "resources": {
      "documentation": ["string"],       // Fichiers markdown, .md
      "chartes": ["string"],             // Fichiers de chartes / fondations
      "autres": ["string"]               // Images, vidéos, modèles, etc.
    },
    "metaprompt": {
      "name": "string",                  // nom du métaprompt utilisé
      "description": { "FR": "string" }  // description du métaprompt
    },
    "exposed": ["string"],              // Variables exposées à l’étape suivante
    "next": "string|null"               // ID de l’étape suivante
  },
  "relations": {
    "inherits_from": "MetaObject",
    "category": "Processus",
    "depends_on": ["MetaPrompt", "MetaMethod"],
    "related_to": ["MetaStep", "MetaValidation"],
    "alias_of": null
  },
  "lifespan": {
    "archive_policy": "versioning",
    "validation_required": true
  },
  "tags": {
    "FR": ["scénario", "étapes", "workflow", "validation", "IA"]
  },
  "transversals": ["MetaValidation", "MetaPrompt", "MetaMethod"]
}


